select * from (

) t
where 1 = 1
and bill_type = #{billType}
and bill_no like concat('%', #{billNo}, '%')
and proj_id = #{projId}
and status = #{status}
and submit_time >= concat(#{beginSubmitTime}, ' 00:00:00')
and submit_time <= concat(#{endSubmitTime}, ' 23:59:59')
order by submit_time desc, bill_id desc
